"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import Image from "next/image";
import { Podium } from "@/components/ui/Podium";

type Dish = { id: string; name: string; avgRank: number };
type ResultsData = { restaurant: { name: string }; rankedDishes: Dish[] };

export default function ResultsDishesPage() {
  const { id } = useParams<{ id: string }>();
  const router = useRouter();
  const [data, setData] = useState<ResultsData | null>(null);

  useEffect(() => {
    fetch(`/api/session/${id}/results`)
      .then((r) => r.json())
      .then(setData);
  }, [id]);

  const top3 = data?.rankedDishes.slice(0, 3) ?? [];
  const rest = data?.rankedDishes.slice(3) ?? [];

  return (
    <main className="min-h-screen bg-[#FFF8E8] flex flex-col items-center px-6 pt-10 pb-10">
      <Image src="/logo.png" alt="playte" width={70} height={70} priority />
      <p className="text-[#9CA3AF] italic text-sm mt-2">{data?.restaurant.name ?? ""}</p>
      <h1 className="text-[#FE392D] text-3xl font-bold mt-1 mb-6">the results are in.</h1>

      {/* Podium */}
      {top3.length >= 1 && (
        <div className="flex items-end justify-center gap-3 w-full max-w-sm px-2">
          {top3[1] && <PodiumColumn place={2} name={top3[1].name} plates={5} />}
          {top3[0] && <PodiumColumn place={1} name={top3[0].name} plates={8} />}
          {top3[2] && <PodiumColumn place={3} name={top3[2].name} plates={3} />}
        </div>
      )}

      {/* Rest of list */}
      <div className="w-full max-w-sm flex flex-col gap-2 mt-6">
        {rest.map((dish, i) => (
          <div
            key={dish.id}
            className="flex items-center gap-3 bg-[#FCCC75]/20 border-2 border-[#FCCC75] rounded-2xl px-4 py-3"
          >
            <span className="text-[#C8A050] text-sm font-semibold w-5 text-right flex-shrink-0">
              {i + 4}
            </span>
            <span className="text-[#646464] text-base">{dish.name}</span>
          </div>
        ))}
      </div>

      {/* Buttons */}
      <div className="w-full max-w-sm flex flex-col gap-3 mt-8">
        <button
          onClick={() => router.push(`/session/${id}/results/flavor`)}
          className="w-full bg-[#FE392D] text-white text-xl font-semibold py-4 rounded-full"
        >
          see flavor journey
        </button>
        <button
          onClick={() => router.push(`/session/${id}/results/players`)}
          className="w-full bg-[#F88888] text-white text-xl font-semibold py-4 rounded-full"
        >
          individual rankings
        </button>
      </div>
    </main>
  );
}
